toolCalls.args:
{"command": "SYMDIR="/tmp/sv-39cd28ee8bb34225ac652cc62d21d7c6/symbols"
DBG="$SYMDIR/libmonosgen-2.0.so.dbg"

# Let me look at what's near these addresses
readelf -sW "$DBG" | awk '/FUNC/{print $2, $3, $NF}' | sort | awk '{
  addr = strtonum("0x"$1)
  if (addr >= 0x2f4000 && addr <= 0x2f5000) print $0
}'", "description": "Find functions near SGen worker addresses", "initial_wait": 10}

arguments.command:
SYMDIR="/tmp/sv-39cd28ee8bb34225ac652cc62d21d7c6/symbols"
DBG="$SYMDIR/libmonosgen-2.0.so.dbg"

# Broader search - these might be LOCAL symbols
readelf -sW "$DBG" | awk '
{
  if ($4 == "FUNC" || $4 == "NOTYPE") {
    addr = strtonum("0x"$2)
    if (addr >= 0x2f4000 && addr <= 0x2f6000) print
  }
}' | head -20
echo "==="
# Also check sections at these addresses
readelf -SW "$DBG" | grep -E "\.text|interp"

